package dao.impl; import dao.CareRecordDao; import model.CareRecord; import util.DBUtil; import java.sql.*; import java.util.*;
public class CareRecordDaoImpl implements CareRecordDao{ private static final List<CareRecord> memory=new ArrayList<>(); static{memory.add(new CareRecord(1,"用藥","2026/07/02","08:00","已服藥","早餐後"));memory.add(new CareRecord(2,"血壓","2026/07/02","09:00","120/80 mmHg","正常"));}
 public List<CareRecord> findAll(){try(Connection c=DBUtil.getConnection();PreparedStatement ps=c.prepareStatement("select * from care_records order by id desc");ResultSet rs=ps.executeQuery()){List<CareRecord> list=new ArrayList<>();while(rs.next())list.add(new CareRecord(rs.getInt("id"),rs.getString("type"),rs.getString("record_date"),rs.getString("record_time"),rs.getString("content"),rs.getString("note")));return list;}catch(Exception e){return memory;}}
 public void create(CareRecord r){try(Connection c=DBUtil.getConnection();PreparedStatement ps=c.prepareStatement("insert into care_records(type,record_date,record_time,content,note) values(?,?,?,?,?)")){ps.setString(1,r.getType());ps.setString(2,r.getDate());ps.setString(3,r.getTime());ps.setString(4,r.getContent());ps.setString(5,r.getNote());ps.executeUpdate();}catch(Exception e){memory.add(r);}}
 public void update(CareRecord r){} public void delete(int id){memory.removeIf(x->x.getId()==id);} }
